func (s *paymentService) CreatePayment(ctx context.Context, req *CreatePaymentRequest) (*Payment, error) {
	if req == nil {
		return nil, status.Error(codes.InvalidArgument, "request is nil")
	}
	if strings.TrimSpace(req.OrderId) == "" {
		return nil, status.Error(codes.InvalidArgument, "order_id is required")
	}
	if req.Amount <= 0 {
		return nil, status.Error(codes.InvalidArgument, "amount must be > 0")
	}
	cur := strings.ToUpper(strings.TrimSpace(req.Currency))
	if cur == "" {
		cur = "USD"
	}

	s.orders.mu.RLock()
	o, ok := s.orders.orders[req.OrderId]
	s.orders.mu.RUnlock()
	if !ok {
		return nil, status.Error(codes.NotFound, "order not found")
	}
	if o.Status == "CANCELLED" {
		return nil, status.Error(codes.FailedPrecondition, "cannot pay cancelled order")
	}

	s.store.mu.Lock()
	defer s.store.mu.Unlock()

	id := s.store.nextID()
	ts := nowUnix()
	p := &Payment{
		Id:        id,
		OrderId:   strings.TrimSpace(req.OrderId),
		Amount:    req.Amount,
		Currency:  cur,
		Status:    "AUTHORIZED",
		CreatedAt: ts,
		UpdatedAt: ts,
	}
	s.store.payments[id] = p

	s.orders.mu.Lock()
	if oo, ok := s.orders.orders[req.OrderId]; ok {
		oo.Status = "PAID"
		oo.UpdatedAt = nowUnix()
	}
	s.orders.mu.Unlock()

	return p, nil
}

