func sortIDs(ids []string) {
	// simple insertion sort by numeric suffix; fine for dev/test sizes
	for i := 1; i < len(ids); i++ {
		j := i
		for j > 0 && idLess(ids[j], ids[j-1]) {
			ids[j], ids[j-1] = ids[j-1], ids[j]
			j--
		}
	}
}

func idLess(a, b string) bool {
	pa, na := splitID(a)
	pb, nb := splitID(b)
	if pa != pb {
		return pa < pb
	}
	return na < nb
}

func splitID(id string) (string, int64) {
	parts := strings.SplitN(id, "_", 2)
	if len(parts) != 2 {
		return id, 0
	}
	n, _ := strconv.ParseInt(parts[1], 10, 64)
	return parts[0], n
}

func unaryLoggingInterceptor() grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req any, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (any, error) {
		start := time.Now()
		resp, err := handler(ctx, req)
		code := status.Code(err)
		log.Printf("grpc method=%s code=%s dur=%s", info.FullMethod, code.String(), time.Since(start))
		return resp, err
	}
}

