func main() {
	addr := os.Getenv("GRPC_ADDR")
	if strings.TrimSpace(addr) == "" {
		addr = ":50051"
	}

	us := &userStore{users: map[string]*User{}}
	osr := &orderStore{orders: map[string]*Order{}}
	ps := &paymentStore{payments: map[string]*Payment{}}

	grpcServer := grpc.NewServer(
		grpc.UnaryInterceptor(unaryLoggingInterceptor()),
	)

	RegisterUserServiceServer(grpcServer, &userService{store: us})
	RegisterOrderServiceServer(grpcServer, &orderService{store: osr, users: us})
	RegisterPaymentServiceServer(grpcServer, &paymentService{store: ps, orders: osr})

	reflection.Register(grpcServer)

	lis, err := net.Listen("tcp", addr)
	if err != nil {
		log.Fatalf("listen error: %v", err)
	}

	log.Printf("gRPC dev server listening on %s", addr)

	errCh := make(chan error, 1)
	go func() {
		errCh <- grpcServer.Serve(lis)
	}()

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	select {
	case sig := <-sigCh:
		log.Printf("signal received: %s, shutting down", sig.String())
		grpcServer.GracefulStop()
	case err := <-errCh:
		log.Printf("server error: %v", err)
	}
}